        let completedSessionsCount = parseInt(localStorage.getItem('agronomia_completed_sessions') || '0');
        const sessionsList = document.getElementById('sessionsList');
        const minimizedSessionBadge = document.getElementById('minimizedSessionBadge');
        const sessionIncBtn = document.getElementById('sessionIncBtn');
