        // ==========================================================================
        // 🧠 QUIZ UNIVERSALE ENGINE
        // ==========================================================================
        function startUniversalQuiz(subject) {
            activeQuizSubject = subject;
            activeQuizIndex = 0;
            quizScoreRight = 0;
            quizScoreTotal = 0;
            
            if (subject === "agronomia") {
                activeQuizList = cardsData.map(card => {
                    return {
                        q: `[Agronomia - ${card.categoria}] Spiega l'argomento: ${card.titolo}`,
                        a: card.descrizione_raw
                    };
                });
            } else if (subject === "biologia") {
                activeQuizList = [];
                Object.keys(cellLabData).forEach(key => {
                    const topic = cellLabData[key];
                    const parser = new DOMParser();
                    const doc = parser.parseFromString(topic.content, 'text/html');
                    const blocks = doc.querySelectorAll('.recall-block');
                    blocks.forEach(block => {
                        const header = block.querySelector('.recall-header');
                        const hidden = block.querySelector('.recall-hidden');
                        if (header && hidden) {
                            activeQuizList.push({
                                q: `[🧬 Biologia - ${topic.title}] ${header.textContent}`,
                                a: hidden.innerHTML
                            });
                        }
                    });
                });
            } else if (subject === "botanica") {
                activeQuizList = quizDatabase.map(item => {
                    return { q: `[🌿 Botanica] ${item.q}`, a: item.a };
                });
            }
            
            activeQuizList.sort(() => Math.random() - 0.5);
            document.getElementById("activeQuizPanel").style.display = "flex";
            loadUniversalQuizCard();
            playAudioTone(1200, 'sine', 0.1);
        }

        function loadUniversalQuizCard() {
            if (activeQuizList.length === 0) {
                document.getElementById("universalQuizQuestion").textContent = "Nessuna domanda disponibile.";
                return;
            }
            
            const card = activeQuizList[activeQuizIndex];
            document.getElementById("universalQuizQuestion").textContent = card.q;
            document.getElementById("universalQuizAnswerText").innerHTML = card.a;
            
            document.getElementById("universalQuizAnswer").style.display = "none";
            document.getElementById("quizInitialActions").style.display = "flex";
            document.getElementById("quizEvaluationActions").style.display = "none";
            
            document.getElementById("quizProgressLabel").textContent = `Domanda ${activeQuizIndex + 1}/${activeQuizList.length}`;
            
            const subjBadges = {
                agronomia: "🚜 Agronomia",
                biologia: "🧬 Biologia",
                botanica: "🌿 Botanica"
            };
            document.getElementById("quizSubjectLabel").textContent = subjBadges[activeQuizSubject];
        }

        function revealUniversalQuizAnswer() {
            document.getElementById("universalQuizAnswer").style.display = "block";
            document.getElementById("quizInitialActions").style.display = "none";
            document.getElementById("quizEvaluationActions").style.display = "flex";
            playAudioTone(850, 'sawtooth', 0.08);
        }

        function submitQuizEvaluation(evalValue) {
            if (evalValue === "good") {
                quizScoreRight++;
                playAudioTone(1100, 'sine', 0.1);
            } else {
                playAudioTone(600, 'triangle', 0.1);
            }
            quizScoreTotal++;
            
            activeQuizIndex++;
            if (activeQuizIndex < activeQuizList.length && activeQuizIndex < 10) {
                loadUniversalQuizCard();
            } else {
                document.getElementById("universalQuizQuestion").innerHTML = `
                    🏆 Round Completato!<br>
                    Materia: <strong style="color:var(--accent);">${activeQuizSubject.toUpperCase()}</strong><br><br>
                    Hai indovinato <strong style="font-size: 2.5rem; color: var(--status-done);">${quizScoreRight}/${quizScoreTotal}</strong> risposte!
                `;
                document.getElementById("universalQuizAnswer").style.display = "none";
                document.getElementById("quizInitialActions").style.display = "flex";
                document.getElementById("quizEvaluationActions").style.display = "none";
                document.getElementById("quizInitialActions").innerHTML = `
                    <button class="header-btn" onclick="startUniversalQuiz('${activeQuizSubject}')" style="padding: 1rem 2rem; background: var(--accent); color: #fff;">🔄 Ripeti Round</button>
                    <button class="header-btn" onclick="switchSubject('quiz-view')" style="padding: 1rem 2rem;">🚪 Torna all'Indice</button>
                `;
                logStudySession();
            }
        }

        function logStudySession() {
            try {
                if (typeof updateActivityGrid === "function") {
                    const today = new Date().toISOString().split('T')[0];
                    let activity = JSON.parse(localStorage.getItem('study_sessions') || '{}');
                    activity[today] = (activity[today] || 0) + 1;
                    localStorage.setItem('study_sessions', JSON.stringify(activity));
                    updateActivityGrid();
                }
            } catch(e) {
                console.error("Activity grid log error: ", e);
            }
        }

        initUnifiedApp();

        // ── UNIFIED OVERRIDES ────────────────────────────────────────────
        function getSmartCategoryLinks(subject) {
            if (subject !== 'agronomia') return {};
            return {
                "Introduzione": ["Introduzione"],
                "Forme di agricoltura": ["Forme di agricoltura"],
                "Suolo": ["Suolo"],
                "Agrometeo": ["Agrometeo"],
                "Lavorazioni": ["Lavorazioni"],
                "Sistemazioni idraulico agrarie": ["Sistemazioni idraulico agrarie", "Drenaggio"],
                "Irrigazione": ["Idrologia", "Metodi irrigui"],
                "Chimica del suolo": ["Fertilizzazione e concimi", "Fertilizzanti non minerali e gestione"],
                "Nutrizione minerale": ["Fertilizzazione e concimi", "Fertilizzanti non minerali e gestione"],
                "Concimazione": ["Fertilizzazione e concimi", "Fertilizzanti non minerali e gestione"],
                "Avversità": ["Malerbologia", "Infestanti importanti"],
                "Erbologia": ["Malerbologia", "Infestanti importanti"],
                "Gestione colture": ["Consociazione avvicendamento", "Malerbologia", "Infestanti importanti"]
            };
        }

        function getFilterCategories(filterName) {
            if (filterName === 'all') return null;
            const links = getSmartCategoryLinks(activeSubject);
            return links[filterName] || [filterName];
        }

        function filterMatchesCategory(filterName, categoryName) {
            if (filterName === 'all') return true;
            const categories = getFilterCategories(filterName);
            return categories ? categories.includes(categoryName) : false;
        }

        function rebuildCategoryTags(subject) {
            const container = document.getElementById('categoryTags');
            if (!container) return;
            const catMap = {
                agronomia: ["Introduzione", "Forme di agricoltura", "Suolo", "Agrometeo", "Lavorazioni", "Sistemazioni idraulico agrarie", "Irrigazione", "Chimica del suolo", "Nutrizione minerale", "Concimazione", "Avversità", "Erbologia", "Gestione colture"],
                biologia:  ["Generalità", "Citologia: La Cellula Vegetale", "Istologia Vegetale", "Organografia: Fusti, Radici e Foglie", "Riproduzione sessuata e asessuata", "Fisiologia Vegetale"],
                botanica:  ["Sistematica: Gimnosperme", "Sistematica: Angiosperme"]
            };
            container.innerHTML = '<button class="tag-btn active" data-category="all">Tutte le categorie</button>';
            (catMap[subject]||[]).forEach(c => {
                container.innerHTML += `<button class="tag-btn" data-category="${c}">${c}</button>`;
            });
            container.querySelectorAll('.tag-btn').forEach(btn => {
                btn.addEventListener('click', () => {
                    container.querySelectorAll('.tag-btn').forEach(b=>b.classList.remove('active'));
                    btn.classList.add('active');
                    currentFilter = btn.getAttribute('data-category');
                    updateFilters();
                    renderDashboardRoadmap();
                    playAudioTone(600,'sine',0.05);
                });
            });
        }

        function switchSubject(subject) {
            activeSubject = subject;
            document.querySelectorAll('.subj-tab').forEach(btn => {
                btn.classList.toggle('active', btn.getAttribute('data-subject') === subject);
            });
            const icons = {agronomia:'🚜', biologia:'🧬', botanica:'🌿'};
            const labels = {agronomia:'Agronomia', biologia:'Biologia', botanica:'Botanica'};
            const li = document.getElementById('logoIcon'); if(li) li.textContent = icons[subject]||'📚';
            const lt = document.getElementById('logoText'); if(lt) lt.textContent = labels[subject]||'Studio';
            if(typeof searchBar!=='undefined' && searchBar) { searchBar.value=''; searchQuery=''; }
            currentFilter = 'all';
            rebuildCategoryTags(subject);
            updateFilters();
            updateTrackerStats();
            renderDashboardRoadmap();
            playAudioTone(1000,'sine',0.08);
        }

        function updateTrackerStats() {
            let total=0, done=0, progress=0, review=0, todo=0, starred=0;
            document.querySelectorAll('.card').forEach(card => {
                if ((card.getAttribute('data-subject')||'agronomia') !== activeSubject) return;
                total++;
                const id = card.getAttribute('data-id');
                const st = studyStates[id] || 'todo';
                if(st==='done') done++; else if(st==='progress') progress++; else if(st==='review') review++; else todo++;
                if(starredCards[id]) starred++;
            });
            const s = (id,v) => { const e=document.getElementById(id); if(e) e.textContent=v; };
            s('lblDone',done); s('lblProgress',progress); s('lblReview',review); s('lblTodo',todo);
            s('countDone',done); s('countProgress',progress); s('countReview',review); s('countStarred',starred);
            const pct = v => total>0 ? (v/total)*100 : 0;
            const b = (id,v) => { const e=document.getElementById(id); if(e) e.style.width=v+'%'; };
            b('barDone',pct(done)); b('barProgress',pct(progress)); b('barReview',pct(review)); b('barTodo',pct(todo));
        }

        function renderDashboardRoadmap() {
            const container = document.getElementById('dashboardRoadmapGrid');
            if (!container) return;
            container.innerHTML = '';
            const galaxies = {};
            document.querySelectorAll('.card').forEach(card => {
                if ((card.getAttribute('data-subject')||'agronomia') !== activeSubject) return;
                const cat = card.getAttribute('data-category') || 'Altro';
                if (!galaxies[cat]) galaxies[cat] = [];
                galaxies[cat].push(card.getAttribute('data-id'));
            });
            Object.entries(galaxies).forEach(([cat, ids], idx) => {
                let done=0;
                ids.forEach(id => { if((studyStates[id]||'todo')==='done') done++; });
                const pct = Math.round((done/ids.length)*100);
                const cardEl = document.createElement('div');
                cardEl.className = 'roadmap-card' + (filterMatchesCategory(currentFilter, cat) ? ' active' : '');
                cardEl.innerHTML = `<div class="roadmap-header"><span class="roadmap-name" title="${cat}"><span style="font-size:.72rem;font-weight:800;opacity:.4;margin-right:.25rem;">#${String(idx+1).padStart(2,'0')}</span>${cat}</span><span class="roadmap-pct">${done}/${ids.length}</span></div><div class="roadmap-bar-bg"><div class="roadmap-bar-fill" style="width:${pct}%"></div></div>`;
                cardEl.addEventListener('click', () => {
                    currentFilter = currentFilter === cat ? 'all' : cat;
                    document.querySelectorAll('#categoryTags .tag-btn').forEach(btn => {
                        const btnFilter = btn.getAttribute('data-category');
                        btn.classList.toggle('active', btnFilter === currentFilter || filterMatchesCategory(btnFilter, currentFilter));
                    });
                    updateFilters(); renderDashboardRoadmap();
                });
                container.appendChild(cardEl);
            });
        }

        function updateFilters() {
            let visibleCount = 0;
            ensureActiveRecallRevealButtons();
            document.querySelectorAll('.card').forEach(card => {
                const cardId = card.getAttribute('data-id');
                const cardCat = card.getAttribute('data-category');
                const cardSearch = card.getAttribute('data-search') || '';
                const cardStatus = studyStates[cardId] || 'todo';
                const isStarred = !!starredCards[cardId];
                const cardSubject = card.getAttribute('data-subject') || 'agronomia';
                const matchesSubject = cardSubject === activeSubject;
                const matchesCategory = filterMatchesCategory(currentFilter, cardCat);
                const matchesSearch = cardSearch.includes(searchQuery);
                let matchesStudyFilter = true;
                if (currentStudyFilter === 'starred') matchesStudyFilter = isStarred;
                else if (currentStudyFilter === 'review') matchesStudyFilter = cardStatus === 'review';
                else if (currentStudyFilter === 'progress') matchesStudyFilter = cardStatus === 'progress';
                else if (currentStudyFilter === 'done') matchesStudyFilter = cardStatus === 'done';
                if (matchesSubject && matchesCategory && matchesSearch && matchesStudyFilter) {
                    card.style.display = 'flex';
                    card.classList.toggle('active-recall-hidden', studyMode === 'recall');
                    visibleCount++;
                } else {
                    card.style.display = 'none';
                    card.classList.remove('active-recall-hidden');
                }
            });
            const emptyState = document.getElementById('emptyState');
            if (emptyState) emptyState.style.display = visibleCount === 0 ? 'flex' : 'none';
        }

    
    // --- INIZIO INTEGRAZIONE WIKIPEDIA LIVE ---
    async function loadWikipediaImages() {
        const botanicaCards = document.querySelectorAll('.card[data-subject="botanica"]');
        botanicaCards.forEach(card => {
            if (card.dataset.imagesLoaded === 'true') return;
            card.dataset.imagesLoaded = 'true';
            
            const speciesItems = card.querySelectorAll('.lead-key i');
            speciesItems.forEach(spNode => {
                const spName = spNode.textContent.trim();
                
                // Crea container
                const imgContainer = document.createElement('div');
                imgContainer.style.display = 'flex';
                imgContainer.style.gap = '0.8rem';
                imgContainer.style.marginTop = '0.6rem';
                spNode.parentNode.appendChild(imgContainer);
                
                // Chiama Wikipedia API dal client (bypassa rate limits e CORS)
                const url = `https://it.wikipedia.org/w/api.php?action=query&prop=pageimages&titles=${encodeURIComponent(spName)}&pithumbsize=400&format=json&origin=*`;
                fetch(url)
                  .then(res => res.json())
                  .then(data => {
                      if(data.query && data.query.pages) {
                          const pages = data.query.pages;
                          for (let id in pages) {
                              if (pages[id].thumbnail) {
                                  const figure = document.createElement('figure');
                                  figure.style.margin = '0';
                                  figure.style.flex = '0 0 auto';
                                  
                                  const img = document.createElement('img');
                                  img.src = pages[id].thumbnail.source;
                                  img.style.height = '140px';
                                  img.style.objectFit = 'cover';
                                  img.style.borderRadius = 'var(--radius-sm)';
                                  img.style.border = '1px solid var(--border-elegant)';
                                  img.alt = spName;
                                  
                                  const cap = document.createElement('figcaption');
                                  cap.style.fontSize = '0.72rem';
                                  cap.style.opacity = '0.65';
                                  cap.style.marginTop = '0.25rem';
                                  cap.style.textAlign = 'center';
                                  cap.textContent = "Fonte: Wikipedia";
                                  
                                  figure.appendChild(img);
                                  figure.appendChild(cap);
                                  imgContainer.appendChild(figure);
                                  return;
                              }
                          }
                      }
                  }).catch(err => console.log('Wikipedia API error per', spName));
            });
        });
    }

    // Aggiungiamo un observer o hook per caricare le immagini quando si apre la tab Botanica
    document.addEventListener('DOMContentLoaded', () => {
        const tabBtns = document.querySelectorAll('.tab-btn');
        tabBtns.forEach(btn => {
            btn.addEventListener('click', (e) => {
                const onclickAttr = e.target.getAttribute('onclick') || '';
                if (onclickAttr.includes('botanica') || e.target.textContent.toLowerCase().includes('botanica')) {
                    setTimeout(() => loadWikipediaImages(), 100);
                }
            });
        });
        
        // Se si parte già su botanica (es. refresh)
        const activeTab = document.querySelector('.tab-btn.active');
        if (activeTab && (activeTab.textContent.toLowerCase().includes('botanica') || (activeTab.getAttribute('onclick') || '').includes('botanica'))) {
            setTimeout(() => loadWikipediaImages(), 100);
        }
    });
    // --- FINE INTEGRAZIONE WIKIPEDIA LIVE ---
